const fs = require("fs");
const path = require("path");

describe("provider credential exposure", () => {
  const repoRoot = path.join(__dirname, "..");

  it.each([
    ["bin/lib/onboard.js", /--credential NVIDIA_API_KEY/],
    ["scripts/setup.sh", /"NVIDIA_API_KEY" \\/],
  ])(
    "%s passes the NVIDIA credential by environment variable name",
    (relativePath, envLookupPattern) => {
      const source = fs.readFileSync(path.join(repoRoot, relativePath), "utf8");

      expect(source).toMatch(envLookupPattern);
      expect(source).not.toContain('"NVIDIA_API_KEY=" + process.env.NVIDIA_API_KEY');
      expect(source).not.toContain('"NVIDIA_API_KEY=$NVIDIA_API_KEY"');
    }
  );
});
